import { defineComponent, computed, h } from 'vue';
import { getLabelClassKeys } from '../lib/core';
import styles from './label.module.scss';

export const TLabel = defineComponent({
  name: 'TLabel',
  props: {
    required: { type: Boolean, default: false },
    htmlFor: String,
  },
  setup(props, { slots }) {
    const classKeys = computed(() => getLabelClassKeys(props.required));
    const classes = computed(() => [
      styles[classKeys.value.base],
      classKeys.value.required ? styles[classKeys.value.required] : '',
    ]);

    return () => h('label', { class: classes.value, for: props.htmlFor }, slots.default?.());
  },
});

export default TLabel;

@use 'variables/colors' as *;

.label {
  display: block;
  font-size: $text-sm;
  font-weight: $font-medium;
  color: $foreground;
  line-height: $leading-normal;
  cursor: pointer;

  &.required::after {
    content: ' *';
    color: $destructive;
  }
}
